public class JsonDiff {

    public static void main(String[] args) throws IOException {
        ObjectMapper mapper = new ObjectMapper();

        // Load two JSON files
        JsonNode json1 = mapper.readTree(new File("file1.json"));
        JsonNode json2 = mapper.readTree(new File("file2.json"));

        compareJsonNodes("", json1, json2);
    }

    private static void compareJsonNodes(String path, JsonNode node1, JsonNode node2) {
        if (node1 == null && node2 == null)
            return;

        if (node1 == null) {
            System.out.println(path + ": field missing in file1, value in file2 = " + node2);
            return;
        }

        if (node2 == null) {
            System.out.println(path + ": field missing in file2, value in file1 = " + node1);
            return;
        }

        if (!node1.getNodeType().equals(node2.getNodeType())) {
            System.out.println(path + ": different types, file1=" + node1.getNodeType() + ", file2=" + node2.getNodeType());
            return;
        }

        switch (node1.getNodeType()) {
            case OBJECT:
                Iterator<Map.Entry<String, JsonNode>> fields = node1.fields();
                while (fields.hasNext()) {
                    Map.Entry<String, JsonNode> entry = fields.next();
                    String currentPath = path.isEmpty() ? entry.getKey() : path + "." + entry.getKey();
                    JsonNode node2Field = node2.get(entry.getKey());
                    compareJsonNodes(currentPath, entry.getValue(), node2Field);
                }
                // Check for fields present in node2 but missing in node1
                Iterator<String> fieldNames = node2.fieldNames();
                while (fieldNames.hasNext()) {
                    String name = fieldNames.next();
                    if (!node1.has(name)) {
                        String currentPath = path.isEmpty() ? name : path + "." + name;
                        System.out.println(currentPath + ": field missing in file1, value in file2 = " + node2.get(name));
                    }
                }
                break;
            case ARRAY:
                int minSize = Math.min(node1.size(), node2.size());
                for (int i = 0; i < minSize; i++) {
                    String currentPath = path + "[" + i + "]";
                    compareJsonNodes(currentPath, node1.get(i), node2.get(i));
                }
                if (node1.size() > node2.size()) {
                    for (int i = node2.size(); i < node1.size(); i++) {
                        String currentPath = path + "[" + i + "]";
                        System.out.println(currentPath + ": element missing in file2, value in file1 = " + node1.get(i));
                    }
                } else if (node2.size() > node1.size()) {
                    for (int i = node1.size(); i < node2.size(); i++) {
                        String currentPath = path + "[" + i + "]";
                        System.out.println(currentPath + ": element missing in file1, value in file2 = " + node2.get(i));
                    }
                }
