    try:
        import yaml
        parsed_data = yaml.safe_load(yaml_content) or {}
    except (ImportError, ModuleNotFoundError):
        # 2) Fallback: JSON is a subset of YAML, so if the input happens to
        #    be JSON we can still parse it.
        try:
            import json
            parsed_data = json.loads(yaml_content or "{}")
        except Exception:
            # If we get here, we could not parse the input; treat it as empty.
            parsed_data = {}
    except Exception:
