class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def build_tree(nodes):
    n = len(nodes)
    if n == 0:
        return None
    treenodes = [TreeNode(val=data[0]) for data in nodes]
    for idx, (val, left, right) in enumerate(nodes):
        if left != -1:
            treenodes[idx].left = treenodes[left]
        if right != -1:
            treenodes[idx].right = treenodes[right]
    return treenodes[0]

def level_order(root):
    if not root:
        return []
    result = []
    queue = [root]
    while queue:
        level = []
        for _ in range(len(queue)):
            node = queue.pop(0)
            level.append(node.val)
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        result.append(level)
    return result

